### KanbanCard.tsx — make it sortable

The existing `KanbanCard` is a plain memo component. Convert it to use `useSortable`:

```tsx
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
// ...

export const KanbanCard = memo(function KanbanCard({ issue, /* ... */ }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: issue.number,
  });
  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0 : 1,
  };
  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners} className="kanban-card-wrapper">
      {/* existing card JSX */}
    </div>
  );
});
```

If the existing card root already has a className/onClick, layer them rather than replace. If the existing component uses motion-from-framer at the card root, the outer wrapper is what gets the sortable handles; the inner motion.div is unchanged.

The `KanbanColumn`'s outer `motion.div` from line 80 in the current code also applies — keep `layoutId={`kanban-card-${issue.number}`}` for cross-column animations.

### KanbanBoard.tsx — handle within-column drag end

In `handleDragEnd` (~line 207), branch on `sourceColumn === targetColumn`:

```tsx
import { arrayMove } from '@dnd-kit/sortable';
// ...

const handleDragEnd = (event: DragEndEvent) => {
  const { active, over } = event;
  setActiveId(null);
  if (!over) return;

  const issueNumber = active.id as number;
  const sourceColumn = getIssueColumn(issueNumber);
  if (!sourceColumn) return;

  // dnd-kit's `over.id` is either a column id (when dropping on empty space)
  // or another issue's number (when hovering over a sibling card).
  const overId = over.id;
  let targetColumn: string;
  if (typeof overId === 'string') {
    targetColumn = overId;
  } else {
    // overId is a number — find which column that issue is in.
    const overIssueColumn = getIssueColumn(overId as number);
    if (!overIssueColumn) return;
    targetColumn = overIssueColumn;
  }

  // Within-column reorder.
  if (sourceColumn === targetColumn) {
    // Build the column's current issue-number list and apply arrayMove.
    const column = columns.find((c) => c.id === sourceColumn);
    if (!column) return;
    const ids = column.issues.map((i) => i.number);
    const fromIdx = ids.indexOf(issueNumber);
    const toIdx = typeof overId === 'number' ? ids.indexOf(overId) : ids.length - 1;
    if (fromIdx === -1 || toIdx === -1 || fromIdx === toIdx) return;
    const reordered = arrayMove(ids, fromIdx, toIdx);
    useKanbanStore.getState().setColumnOrder(sourceColumn, reordered);
    return;
  }

  // Cross-column transition (existing logic).
  if (!isValidTransition(sourceColumn, targetColumn)) {
    console.log(`Invalid transition: ${sourceColumn} → ${targetColumn}`);
    return;
  }
  if (targetColumn === 'execute') {
    triggerExecution(issueNumber, sourceColumn);
  } else if (targetColumn === 'shipping' && sourceColumn === 'execute') {
    requestShipConfirmation(issueNumber);
  }
};
```

### Reset-order affordance — KanbanColumn header

