```tsx
const hasCustomOrder = useKanbanStore((s) => Boolean(s.orderByColumnByProject[projectId]?.[id]?.length));

// In the column header JSX:
{hasCustomOrder && (
  <button
    type="button"
    className="kanban-column-reset"
